def kth_ordered(words, k):
    if k < 1 or k > len(words):
        return None

    # Group words by their length
    groups = {}
    for word in words:
        length = len(word)
        if length not in groups:
            groups[length] = []
        groups[length].append(word)

    # Sort each group reverse-alphabetically
    for group in groups.values():
        group.sort(reverse=True)

    sorted_words = []
    # Flatten the list of lists into a single sorted list
    for group in groups.values():
        sorted_words.extend(group)

    return sorted_words[k-1]
